INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('retired-7ec62a85-moex-00113', 'retired-7ec62a85', 'retired-7ec62a85-moex-114-3082b5f1', 'sub-retired-7ec62a85-04', NULL, 'single_choice', '甲登記為公職人員選舉候選人，因主管機關認其資格與規定不合而駁回。甲不服提起訴願，遭訴 願駁回，乃提起行政訴訟。甲應提起何種類型之行政訴訟？', '["撤銷訴訟", "課予義務訴訟", "確認訴訟", "一般給付訴訟"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:25+00:00", "source_pdf_sha1": "08231c21eb42", "answer_pdf_sha1": "647b6f5bbf6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "135", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('retired-7ec62a85-moex-00114', 'retired-7ec62a85', 'retired-7ec62a85-moex-114-3082b5f1', 'sub-retired-7ec62a85-04', NULL, 'single_choice', '依司法院解釋意旨，有關國家賠償法就有審判或追訴職務之公務員所設之特別規定，下列敘述何 者正確？', '["一、二審判決有罪，三審無罪定讞者，被告得請求賠償", "該特別規定違反平等原則", "法院適用法律見解有誤時，人民得請求賠償", "係基於國家機關功能之差別所設規定"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:25+00:00", "source_pdf_sha1": "08231c21eb42", "answer_pdf_sha1": "647b6f5bbf6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "135", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('retired-7ec62a85-moex-00115', 'retired-7ec62a85', 'retired-7ec62a85-moex-114-3082b5f1', 'sub-retired-7ec62a85-04', NULL, 'single_choice', '關於行政損失補償之敘述，下列何者正確？', '["警察不當使用警械，因此對人民所生之財產填補應屬於損失補償", "合法行政處分之廢止，乃是基於公益之追求，無損失補償之問題", "對消防人員破門救火行為所為之補償，屬於合法即時強制行為之損失補償，其補償以金錢為限", "行政私法行為在追求公共任務之履行，故亦有可能成立損失補償"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:25+00:00", "source_pdf_sha1": "08231c21eb42", "answer_pdf_sha1": "647b6f5bbf6b", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "135", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('retired-7ec62a85-moex-00116', 'retired-7ec62a85', 'retired-7ec62a85-moex-112-8d1d3a67', 'sub-retired-7ec62a85-05', NULL, 'essay', '張三傷害致死的案件審判中，檢察官提出監視錄影器的影像，以及被害
人李四生前於警詢時作成的陳述作為證據。張三主張，該影像紀錄及李
四於警詢時的陳述都是傳聞，無證據能力。試問，張三的主張有無理由？
請附詳細理由說明。（35分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:25+00:00", "source_pdf_sha1": "e04a9157a8c3", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "137", "s": "0906", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑事訴訟法", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('retired-7ec62a85-moex-00117', 'retired-7ec62a85', 'retired-7ec62a85-moex-112-8d1d3a67', 'sub-retired-7ec62a85-05', NULL, 'essay', '警察前往嫌疑人張三租屋處，敲門後，無人應門。警察遂通知張三的房
東李四，李四得知張三涉嫌買賣毒品後，同意配合辦案，交出張三房間
的鑰匙。警察進入進行搜索，並在房間書桌的抽屜裡發現數包毒品。審
判中，檢察官提出該毒品作為證據，證明張三販賣毒品的事實。請問，
警察取得毒品的程序是否合法？有無證據能力？（35分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:25+00:00", "source_pdf_sha1": "e04a9157a8c3", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "137", "s": "0906", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑事訴訟法", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('retired-7ec62a85-moex-00118', 'retired-7ec62a85', 'retired-7ec62a85-moex-112-8d1d3a67', 'sub-retired-7ec62a85-05', NULL, 'essay', '就張三的強盜案件，檢察官於偵查後提起公訴，於準備程序中，張三未
選任辯護人，法院亦未為其指定辯護人。法院所進行的準備程序，是否
合法？請附詳細理由說明。（30分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:25+00:00", "source_pdf_sha1": "e04a9157a8c3", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "137", "s": "0906", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑事訴訟法", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('retired-7ec62a85-moex-00119', 'retired-7ec62a85', 'retired-7ec62a85-moex-112-916530c6', 'sub-retired-7ec62a85-06', NULL, 'essay', '甲在犯罪組織中擔任打雜工作，某日目睹該組織首腦乙拿刀刺死叛逃組
織的小弟 A。在乙受到檢察官的犯罪調查時，乙知悉甲有看到其殺害 A
的情狀，竟在甲收到檢察官的證人傳喚通知後，將甲叫到身前對甲冷笑
說：「如果你向檢方說明你有看到我殺 A，可能上天不知道什麼時候一把
無名火就把你全家燒光光，或者不知道為什麼全家突然因為不明原因死
光光。你保佑自己和全家平安的方式，我看就是跟檢方說我是清白無辜
的」。甲知道乙向來做事殘暴，並有一群小弟受其支配從事犯罪行為，心
裡極為恐懼，甲因此在檢方偵查作證時，雖已具結，卻仍偽稱案發當日
乙不在現場，且願意擔任乙並沒有在現場的目擊證人。試問甲、乙的行
為依刑法如何論處？（50分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:26+00:00", "source_pdf_sha1": "cbc82518a0a7", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "137", "s": "0902", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑法", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('retired-7ec62a85-moex-00120', 'retired-7ec62a85', 'retired-7ec62a85-moex-112-916530c6', 'sub-retired-7ec62a85-06', NULL, 'essay', '甲在酒館喝酒，離開時甲知道自己已有醉意，於是在街邊召喚並搭乘乙
所駕駛之計程車回家。在計程車上，甲原想利用機會在車上小睡，不料
剛閉上眼時，被重大震動驚醒。原來乙在停等紅綠燈時，被後車追撞。
乙額頭輕微擦傷而流血，血跡從外觀上很像乙的臉部受到重大傷害，乙
受到撞擊回神後，從照後鏡看到自己，以為有毀容的傷害危險，乙竟不
顧事故處理，直接攔停另一台計程車赴醫。甲看著乙搭上計程車離去，
認為乙不可以一走了之，應留在現場。甲覺得乙是現行犯，任何人都可
以逮捕，甲看到路邊有一台外送服務人員的機車沒熄火停在路邊，雖然
機車主人不在，甲仍以借用的想法直接騎上該機車追趕並準備攔停乙所
搭乘的計程車。不料甲因不勝酒力無法駕馭機車，在轉彎時甲連同機車
摔倒在路邊，機車後的貨品因此甩出，剛好擊中一名路人 A的鼻梁，使
得 A流鼻血。警察到場處理後，對甲進行酒測，甲吐氣所含酒精濃度為
每公升 0.18毫克。試問甲、乙的行為依刑法如何論處？（50分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:26+00:00", "source_pdf_sha1": "cbc82518a0a7", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "137", "s": "0902", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑法", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('retired-7ec62a85-moex-00121', 'retired-7ec62a85', 'retired-7ec62a85-moex-112-13504c0c', 'sub-retired-7ec62a85-01', NULL, 'single_choice', '下列文句「」中的成語，何者使用正確？', '["今天氣溫驟降，乍暖還寒，他雖已穿上外套，仍然覺得「不寒而慄」", "疫情趨緩，管制措施取消，週末遊樂場重新開放，人潮「不絕如縷」", "全面網路教學，不像在教室上課，老師可以直接對學生「移樽就教」", "網路上有各種消息與傳聞，需仔細辨明查證，是否只是「空穴來風」"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:26+00:00", "source_pdf_sha1": "12b40987f5c4", "answer_pdf_sha1": "0ddd4b93b580", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "137", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(作文與測驗)", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "法律廉政"}'::jsonb, NULL),
  ('retired-7ec62a85-moex-00122', 'retired-7ec62a85', 'retired-7ec62a85-moex-112-13504c0c', 'sub-retired-7ec62a85-01', NULL, 'single_choice', '「近代民族國家的形成，無疑促進了各國（特別是各小國）從過去歷史中去尋求民 族文化及其經典系列的努力。能夠尋找出這樣一個系列，並且讓世界各國接受與承 認，無疑可以增進民族的尊嚴與自豪。近代所形成的各級教育體系，也促進了這種 作用。各國在語言教育及人文教育中，都會把經典作品按其程度的深淺，選入各級 教育的教材中，以便讓他們的人民，學習到這一『傳統』，從『認識』中得到『認 同』，並由此而獲得『民族感情』。」 根據上文，下列敘述何者最符合作者立論？', '["一個民族國家的人文經典，時常需要從歷史中找尋，同時透過後天教育體制來發 展與建構", "近代民族國家的形成，需要受到世界各國的接受與承認，所以吸收西方思想與方 法是必要的歷程", "民族感情跟民族認同有關，民族認同又與傳統有關，因此應該積極地講究復古， 因為復古即傳統", "各級教育有形塑民族人文經典的功能，因此尚未成熟的作品，基於保護和提攜， 還是應該選入教材"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:26+00:00", "source_pdf_sha1": "12b40987f5c4", "answer_pdf_sha1": "0ddd4b93b580", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "137", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(作文與測驗)", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "retired", "civil_category": "法律廉政"}'::jsonb, NULL)
